import * as fields from '../../../../../assets/src/index.tsx'
import userEvent from '@testing-library/user-event'
import { 
  render, 
  within 
} from '@testing-library/react'
import { 
  rendersWithMinimal,
  rendersWithoutLabelThrowWarning,
  rendersLabelAndDescription
} from '../../../utils/fields.ts'

describe('Checkbox component', () => {

  it('renders with minimal config', () => rendersWithMinimal({ type: 'checkbox' }))
  it('renders when no label but throws a warning', () => rendersWithoutLabelThrowWarning({ type: 'checkbox' }))
  it('renders label and description', () => rendersLabelAndDescription({ type: 'checkbox' }))

  it('triggers checked change if label is clicked', async () => {

    const user = userEvent.setup()
    const { container } = render( 
      fields.render({
        label   : 'Click on label',
        name    : 'checkbox-name',
        type    : 'checkbox',
      })
    )

    const input = container.querySelector('input[type="checkbox"]')
    expect(input.checked).toBe(false)

    await user.click(within(container).getByText('Click on label'))

    expect(input.checked).toBe(true)
  })
})

import { 
  render,
  screen
} from '@testing-library/react'
import * as fields from '../../../assets/src/index.tsx'

const rendersWithMinimal = ({
  type,
  expectedClass
}) => {

  const { container } = render(
    fields.render({
      type  : type,
      label : `Label for ${type}`
    }
  ))

  const classes = container.firstChild.firstChild.classList
  expect(classes.contains(expectedClass ?? `tf-${type}`)).toEqual(true)
}

const rendersWithoutLabelThrowWarning = ({
  type,
  expectedClass
}) => {

  console.warn = jest.fn()

  const { container } = render(
    fields.render({
      type : type
    }
  ))

  const classes = container.firstChild.firstChild.classList

  expect(classes.contains(expectedClass ?? `tf-${type}`)).toEqual(true)
  expect(console.warn).toHaveBeenCalled()
}

const rendersLabelAndDescription = ({
  type,
  expectedClass
}) => {

  const { container } = render(
    fields.render({
      type        : type,
      label       : `Label for ${type}`,
      description : `Description for ${type}`
    }
  ))

  const classes = container.firstChild.firstChild.classList

  expect(classes.contains(expectedClass ?? `tf-${type}`)).toEqual(true)

  const label = screen.getByText(`Label for ${type}`)
  const description = screen.getByText(`Description for ${type}`)

  expect(label).toBeTruthy()
  expect(description).toBeTruthy()
}

const renderHasElement = (config, getElement) => {

  const { container } = render(fields.render(config))
  const element = getElement(container)

  expect(element).toBeTruthy()
}

const renderHasNotElement = (config, getElement) => {

  const { container } = render(fields.render(config))
  const element = getElement(container)

  expect(element).toBeFalsy()
} 

export {
  rendersWithMinimal,
  rendersWithoutLabelThrowWarning,
  rendersLabelAndDescription,
  renderHasElement,
  renderHasNotElement
}
